.darma-loader-darma-custom-498 {color: var(--loader-color, #f97316);
   width: calc(80px*0.707);
   height: calc(80px*0.707);
   background: var(--loader-color, #f97316);
   clip-path: polygon(0 0,50% 15%,100% 0,85% 50%,100% 100%,50% 85%,0 100%,15% 50%);
   -webkit-mask: radial-gradient(circle closest-side,#0000 92%,currentColor) top /100% 33.4%, radial-gradient(circle closest-side,#0000 92%,currentColor) left /33.4% 33.4%, radial-gradient(circle 5px ,#0000 92%,currentColor) center/33.3% 33.3%, radial-gradient(circle closest-side,#0000 92%,currentColor) right /33.4% 33.4%, radial-gradient(circle closest-side,#0000 92%,currentColor) bottom/100% 33.4%;
   -webkit-mask-repeat: no-repeat;
   animation: darma-loader-darma-custom-498-l4 1.5s infinite linear;
}
@keyframes darma-loader-darma-custom-498-l4  {
  100%{transform: rotate(1turn)}
}

